            op = self.advance().value
            right = self.parse_term()
            left = BinaryOp(op, left, right)
        return left

    def parse_factor(self) -> Expression:
        left = self.parse_unary()
        while self.peek().value in ("*", "/", "%"):
            op = self.advance().value
            right = self.parse_factor()
            left = BinaryOp(op, left, right)
        return left

    def parse_unary(self) -> Expression:
        if self.peek().value in ("!", "-"):
            op = self.advance().value
            operand = self.parse_unary()
            return UnaryOp(op, operand)
        return self.parse_call()

    def parse_call(self) -> Expression:
        callee = self.parse_primary()
        while self.peek().value in ("(", "["):
            if self.peek().value == "(":
                self.advance()  # consume (
                args = []
                if self.peek().value != ")":
                    while True:
                        args.append(self.parse_expression())
                        if self.peek().value == ",":
                            self.advance()  # consume comma
                        else:
                            break
                self.match("PUNCT")  # )
                callee = Call(callee, args)
            elif self.peek().value == "[":
                self.advance()  # consume [
                key = self.parse_expression()
                self.match("PUNCT")  # ]
                callee = Index(callee, key)
        return callee

    def parse_primary(self) -> Expression:
        token = self.peek()
        if token.kind == "NUMBER":
            self.advance()
            return NumberLit(token.value)
        elif token.kind == "STRING":
            self.advance()
            return StringLit(token.value)
        elif token.kind == "KEYWORD":
            keyword = token.value
            if keyword == "true":
                self.advance()
                return BoolLit(True)
            elif keyword == "false":
                self.advance()
                return BoolLit(False)
            elif keyword == "nil":
                self.advance()
                return NilLit()
            elif keyword == "fn":
                return self.parse_fn_lit()
            else:
                raise ParseError(f"Unexpected keyword '{keyword}'", token.line, token.col)
        elif token.kind == "IDENT":
            self.advance()
            return Identifier(token.value)
        elif token.kind == "PUNCT" and token.value == "(":
            self.advance()  # consume (
            expr = self.parse_expression()
            self.match("PUNCT")  # )
            return expr
        elif token.kind == "PUNCT" and token.value == "[":
            return self.parse_list_lit()
        elif token.kind == "PUNCT" and token.value == "{":
            return self.parse_dict_lit()
        else:
            raise ParseError(f"Unexpected token {token.kind} with value {token.value}", token.line, token.col)

    def parse_list_lit(self) -> ListLit:
        self.match("PUNCT")  # [
        items = []
        if self.peek().value != "]":
            while True:
                items.append(self.parse_expression())
                if self.peek().value == ",":
                    self.advance()  # consume comma
                    if self.peek().value == "]":  # trailing comma
                        break
                else:
                    break
        self.match("PUNCT")  # ]
        return ListLit(items)

    def parse_dict_lit(self) -> DictLit:
        self.match("PUNCT")  # {
        pairs = []
        if self.peek().value != "}":
            while True:
                key = self.parse_expression()
                self.match("PUNCT")  # :
                value = self.parse_expression()
                pairs.append((key, value))
                if self.peek().value == ",":
                    self.advance()  # consume comma
                    if self.peek().value == "}":  # trailing comma
                        break
                else:
                    break
        self.match("PUNCT")  # }
        return DictLit(pairs)

    def parse_fn_lit(self) -> FnLit:
        self.match_value("fn")
        self.match("PUNCT")  # (
        params = []
        if self.peek().value != ")":
            while True:
                param = self.match("IDENT").value
                params.append(param)
                if self.peek().value == ",":
                    self.advance()  # consume comma
                else:
                    break
        self.match("PUNCT")  # )
        body = self.parse_block()
        return FnLit(params, body)

def parse(source_or_tokens) -> Program:
    if isinstance(source_or_tokens, str):
        tokens = tokenize(source_or_tokens)
    else:
        tokens = source_or_tokens
    parser = Parser(tokens)
    return parser.parse_program()

